  phrases: [{ hi: "बिना मिर्च, कृपया।", de: "Ohne Chili, bitte.", ipa: "bɪnaː mɪrtʃ krɪpəjaː" }, { hi: "कम नमक चाहिए।", de: "Ich möchte weniger Salz.", ipa: "kəm nəmək tʃaːhije" }, { hi: "चीनी मत डालिए।", de: "Geben Sie keinen Zucker hinein.", ipa: "tʃiːniː mət ɖaːlije" }, { hi: "क्या यह ताज़ा है?", de: "Ist das frisch?", ipa: "kjaː jəh taːzaː hɛː" }, { hi: "मुझे साफ़ पानी चाहिए।", de: "Ich brauche sauberes Wasser.", ipa: "mʊdʒʱeː saːf paːniː tʃaːhije" }],
